class Solution:
    def canTransform(self, start: str, result: str) -> bool:
        if start.replace("X","") != result.replace("X",""): return False
        def strip(s):
            i, j = 0, len(s)-1
            while i <= j:
                if s[i] in "LR": break
                i += 1
            while j >= i:
                if s[j] in "LR": break
                j -= 1
            return s[i:j+1]
        return strip(start) == strip(result) and start.replace("X","")==result.replace("X","")

